CREATE OR REPLACE FUNCTION trigger_fct_tbiu_sc_hr_off_salary_paid() RETURNS trigger AS $BODY$
BEGIN
  BEGIN
  if coalesce(trim(both NEW.bank_code)::text, '') = '' then
    BEGIN
        select bank_code
        into STRICT NEW.bank_code
        from sc_hr_off_member
        where NEW.official_no = official_no;
    exception when no_data_found then null;
    end;


    if coalesce(trim(both NEW.bank_code)::text, '') = '' then
        NEW.bank_code := '006';
    end if;

end if;
  END;
RETURN NEW;
end
